              <span className='text-lg text-muted-foreground'>/ 100</span>
              <span className={`flex items-center gap-1.5 text-sm font-medium ${levelStyle.color}`}>
                <span className={`size-2 rounded-full ${levelStyle.dot}`} />
                {levelLabel}
              </span>
