          CG #{coingeckoRank}
        </span>
      ) : null}
      {coinmarketcapRank ? (
        <span className='rounded-full border border-sky-500/20 bg-sky-500/10 px-2 py-0.5 text-[10px] font-medium text-sky-700'>
          CMC #{coinmarketcapRank}
