  );
}

function MetricCard({
  label,
  value,
  tone,
  accent,
}: {
  label: string;
  value: string;
  tone?: number | null;
  accent?: string;
}) {
  const toneClass =
    tone === undefined || tone === null
      ? ''
      : tone > 0
        ? 'text-emerald-600'
