  return (
    <div className={`rounded-xl border bg-background/60 p-3 ${accentClass}`}>
      <p className='text-[10px] uppercase tracking-[0.14em] text-muted-foreground'>{label}</p>
      <p className={`mt-1 text-sm font-semibold ${toneClass}`}>{value}</p>
    </div>
