// ── Weekly Research ───────────────────────────────────────────────────────────

interface WeeklyReport {
  id: string;
  dateRange: string;
  headline: string;
  crypto?: string[];
  macro?: string[];
  aiTech?: string[];
}

const WEEKLY_REPORTS: Record<WeeklySubTab, WeeklyReport[]> = {
  focus: [
    {
      id: '2026-W17',
      dateRange: 'Apr 14 – Apr 20, 2026',
      headline: 'SOL 继续领跑，ETH 生态基础设施二季度回暖信号',
      crypto: [
        'SOL ALT/BTC 保持历史高位附近，未见明显分配压力。',
        'ETH L2 链上活跃度环比 +12%，STRK/ARB 等基础设施代币开始从底部企稳。',
        'HYPE 周线连续两根阳线，交易量未萎缩，HODL 信号明确。',
      ],
      macro: [
        '美联储 5 月加息预期降温，流动性边际宽松预期支撑风险资产。',
        '美股科技板块回调 3% 后反弹，加密与纳斯达克相关性仍高。',
      ],
      aiTech: [
        'OpenAI 发布 GPT-5 mini，推理成本下降，AI 应用赛道新一轮融资潮开启。',
        'Base 链 AI Agent 部署量周环比 +38%，on-chain AI 叙事升温。',
      ],
    },
  ],
  breadth: [
    {
      id: '2026-W17',
      dateRange: 'Apr 14 – Apr 20, 2026',
      headline: '市场广度扩张：Top 500 中 61% 山寨币本周正收益',
      crypto: [
        'Top 500 山寨币正收益占比 61%，较上周 48% 明显扩张，市场广度改善。',
        'DeFi 板块领涨，TVL 周内增加 $2.1B，AAVE/UNI 相对强势。',
        '交易所代币板块继续弱势，BNB/OKB 跑输 BTC 约 4%。',
        'Meme 板块分化加剧，DOGE 维持，PEPE/SHIB 相对 BTC 走弱。',
      ],
      macro: [
        '全球风险偏好回升，黄金/加密同涨结构出现，资金流入信号正面。',
      ],
      aiTech: [
        'AI 代币板块（TAO/RENDER/FET）整体跑赢 BTC，平均超额 +6%。',
        'TAO 质押量突破历史新高，AI + DePIN 叙事持续获得机构关注。',
      ],
    },
  ],
  heat: [
    {
      id: '2026-W17',
      dateRange: 'Apr 14 – Apr 20, 2026',
      headline: 'BTC 热度维持中性偏暖，MVRV 未进入贪婪区间',
      crypto: [
        'BTC 周线收于 $87,200，在 $85K 支撑上方站稳，多头结构完整。',
        'MVRV Z-Score 3.1，处于中性区间，距历史顶部泡沫区（>7）尚有距离。',
        'NUPL 周内小幅升至 0.58（Belief/Denial 边界），未见顶部信号。',
        'Exchange Netflow 为负值，资金持续净流出交易所，强 HODL 信号。',
      ],
      macro: [
        '美元指数 DXY 跌破 102，BTC/黄金相关性回升至 0.72，宏观顺风。',
        '美国 CPI 数据略低于预期，通胀继续降温，加密市场积极反应。',
        '日元汇率压力缓和，套利交易拆解风险降低，新兴市场流动性改善。',
      ],
      aiTech: [
        'Meta AI 发布新一代多模态模型，参数规模达 1T，AI 军备竞赛加速。',
        'Anthropic 季度融资 $2.5B，AI 基础设施投资持续高热。',
        '微软 Build 2026 公告：Azure AI 推理集群规模扩大 4 倍，算力叙事利好 GPU 代币。',
      ],
    },
  ],
};

const WEEKLY_SUB_LABELS: Record<WeeklySubTab, string> = {
  focus: 'Research Focus',
  breadth: 'Altcoin Breadth',
  heat: 'BTC Market Heat',
};

function WeeklySectionTag({ label }: { label: string }) {
  return (
    <span className='inline-block rounded-full border border-border/60 bg-muted/60 px-2.5 py-0.5 text-[10px] font-semibold uppercase tracking-widest text-muted-foreground'>
      {label}
    </span>
  );
}

function WeeklyReportCard({ report }: { report: WeeklyReport }) {
  return (
    <div className='rounded-2xl border border-border/70 bg-background/80 shadow-sm shadow-black/5 overflow-hidden'>
      <div className='flex items-start justify-between gap-4 border-b border-border/50 px-5 py-4'>
        <div className='space-y-0.5'>
          <p className='text-[11px] font-medium tracking-widest text-muted-foreground uppercase'>{report.dateRange}</p>
          <h3 className='text-sm font-semibold leading-snug tracking-tight'>{report.headline}</h3>
        </div>
        <span className='shrink-0 rounded-full bg-amber-500/15 px-2.5 py-1 text-[10px] font-semibold uppercase tracking-widest text-amber-600'>
          周报
        </span>
      </div>
      <div className='divide-y divide-border/40'>
        {report.crypto && report.crypto.length > 0 ? (
          <div className='px-5 py-4 space-y-2.5'>
            <WeeklySectionTag label='Crypto' />
            <ul className='space-y-1.5'>
              {report.crypto.map((item, i) => (
                <li key={i} className='flex items-start gap-2 text-sm text-muted-foreground leading-relaxed'>
                  <span className='mt-1.5 h-1 w-1 shrink-0 rounded-full bg-foreground/40' />
                  {item}
                </li>
              ))}
            </ul>
          </div>
        ) : null}
        {report.macro && report.macro.length > 0 ? (
          <div className='px-5 py-4 space-y-2.5'>
            <WeeklySectionTag label='Macro' />
            <ul className='space-y-1.5'>
              {report.macro.map((item, i) => (
                <li key={i} className='flex items-start gap-2 text-sm text-muted-foreground leading-relaxed'>
                  <span className='mt-1.5 h-1 w-1 shrink-0 rounded-full bg-foreground/40' />
                  {item}
                </li>
              ))}
            </ul>
          </div>
        ) : null}
        {report.aiTech && report.aiTech.length > 0 ? (
          <div className='px-5 py-4 space-y-2.5'>
            <WeeklySectionTag label='AI & Tech' />
            <ul className='space-y-1.5'>
              {report.aiTech.map((item, i) => (
                <li key={i} className='flex items-start gap-2 text-sm text-muted-foreground leading-relaxed'>
                  <span className='mt-1.5 h-1 w-1 shrink-0 rounded-full bg-foreground/40' />
                  {item}
                </li>
              ))}
            </ul>
          </div>
        ) : null}
      </div>
    </div>
  );
}

function WeeklyResearchTab() {
  const [sub, setSub] = useState<WeeklySubTab>('focus');
  const reports = WEEKLY_REPORTS[sub];
  return (
    <div className='space-y-6'>
      <div className='space-y-1'>
        <h2 className='text-xl font-semibold tracking-tight'>Weekly Research</h2>
        <p className='text-sm text-muted-foreground'>
          每周加密货币、宏观经济与 AI 科技领域的研究更新。按板块分类浏览，覆盖 Crypto、Macro、AI & Tech 三大维度。
        </p>
      </div>
      <div className='flex flex-wrap gap-2'>
        {(Object.keys(WEEKLY_SUB_LABELS) as WeeklySubTab[]).map((key) => (
          <button
            key={key}
            onClick={() => setSub(key)}
            className={`rounded-full border px-3 py-1.5 text-xs transition-colors ${
              sub === key
                ? 'border-foreground bg-foreground text-background'
                : 'border-border bg-background text-muted-foreground hover:border-foreground/30'
            }`}
          >
            {WEEKLY_SUB_LABELS[key]}
          </button>
        ))}
      </div>
      {reports.length === 0 ? (
        <p className='rounded-2xl border border-dashed border-border px-4 py-10 text-center text-sm text-muted-foreground'>
          该板块暂无周报内容。
        </p>
      ) : (
        <div className='space-y-4'>
          {reports.map((report) => (
            <WeeklyReportCard key={report.id} report={report} />
          ))}
        </div>
      )}
    </div>
  );
}

