};

type FocusFilterTab = 'all' | 'S' | 'A' | 'B' | 'F';
type UniverseFilterTab = 'all' | 'research' | 'binance' | 'dual' | 'positive7d';
type MainTab = 'focus' | 'breadth' | 'heat' | 'weekly';
