// ── BTC Heat API types ──────────────────────────────────────────────────────

interface BtcIndicator {
  name: string;
  value: number | null;
  score: number;
  weight: number;
  group: string;
}

interface BtcScoreData {
  btcPrice: number;
  score: number;
  dailyScore: number;
  weeklyScore: number;
  level: string;
  suggestion: string;
  indicators: BtcIndicator[];
  timestamp?: string;
  _cached?: boolean;
}

// ── Formatters ──────────────────────────────────────────────────────────────

function formatPct(value: number | null): string {
  if (value === null || value === undefined) return 'N/A';
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(2)}%`;
}

function formatUsd(value: number | null): string {
  if (value === null || value === undefined) return 'N/A';
  if (value >= 1e9) return `$${(value / 1e9).toFixed(2)}B`;
  if (value >= 1e6) return `$${(value / 1e6).toFixed(2)}M`;
  if (value >= 1e3) return `$${(value / 1e3).toFixed(2)}K`;
  return `$${value.toFixed(2)}`;
}

function formatVolumeRatio(value: number | null): string {
  if (value === null || value === undefined) return 'N/A';
  return `${(value * 100).toFixed(2)}%`;
}

function formatSnapshotTimestamp(value: string | null): string {
  if (!value) return 'N/A';
  return new Date(value).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

function formatSnapshotAge(value: string | null): string {
  if (!value) return 'N/A';
  const now = Date.now();
  const ts = new Date(value).getTime();
  const diffMs = now - ts;
  const diffDays = Math.floor(diffMs / 86400000);
  if (diffDays === 0) return 'Updated today';
  if (diffDays === 1) return '1 day ago';
  return `${diffDays} days ago`;
}

