          {weeklyIndicators.map((ind) => (
            <BtcHeatIndicatorCard key={ind.name} indicator={ind} />
          ))}
        </div>
      </div>

      {/* BTC Heat FAQ */}
      <FaqSection items={BTC_HEAT_FAQ} />
    </div>
  );
}

