// ── Weekly Research ───────────────────────────────────────────────────────────

interface WeeklyReport {
  id: string;
  dateRange: string;
  headline: string;
  crypto?: string[];
  macro?: string[];
  aiTech?: string[];
}

const WEEKLY_REPORTS: WeeklyReport[] = [
  {
    id: '2026-W17',
    dateRange: 'Apr 14 – Apr 20, 2026',
    headline: 'BTC 热度中性偏暖，山寨广度扩张，AI 代币板块领跑',
    crypto: [
      'BTC 周线收于 $87,200，$85K 支撑完整，MVRV Z-Score 3.1 处于中性区间。',
      'Top 500 山寨币正收益占比 61%，较上周 48% 明显扩张，市场广度显著改善。',
      'SOL ALT/BTC 保持历史高位附近，未见明显分配压力；HYPE 周线连续两根阳线。',
      'DeFi 板块领涨，TVL 周内增加 $2.1B，AAVE/UNI 相对强势。',
      'Exchange Netflow 为负值，资金持续净流出交易所，强 HODL 信号。',
    ],
    macro: [
      '美元指数 DXY 跌破 102，BTC/黄金相关性回升至 0.72，宏观顺风。',
      '美国 CPI 数据略低于预期，通胀继续降温，美联储 5 月加息预期降温。',
      '美股科技板块回调 3% 后反弹，加密与纳斯达克相关性仍高。',
      '日元汇率压力缓和，套利交易拆解风险降低，新兴市场流动性改善。',
    ],
    aiTech: [
      'AI 代币板块（TAO/RENDER/FET）整体跑赢 BTC，平均超额 +6%，TAO 质押量突破历史新高。',
      'OpenAI 发布 GPT-5 mini，推理成本下降，AI 应用赛道新一轮融资潮开启。',
      'Meta AI 发布新一代多模态模型（参数规模 1T），AI 军备竞赛加速。',
      'Anthropic 季度融资 $2.5B；微软 Build 2026：Azure AI 推理集群规模扩大 4 倍。',
      'Base 链 AI Agent 部署量周环比 +38%，on-chain AI + DePIN 叙事持续升温。',
    ],
  },
];

function WeeklySectionTag({ label, color }: { label: string; color: string }) {
  return (
    <span className={`inline-block rounded-full border px-2.5 py-0.5 text-[10px] font-semibold uppercase tracking-widest ${color}`}>
      {label}
    </span>
  );
}

const SECTION_META = [
  {
    key: 'crypto' as const,
    label: 'Crypto',
    color: 'border-sky-500/30 bg-sky-500/10 text-sky-600',
    dot: 'bg-sky-500/60',
  },
  {
    key: 'macro' as const,
    label: 'Macro',
    color: 'border-violet-500/30 bg-violet-500/10 text-violet-600',
    dot: 'bg-violet-500/60',
  },
  {
    key: 'aiTech' as const,
    label: 'AI & Tech',
    color: 'border-amber-500/30 bg-amber-500/10 text-amber-600',
    dot: 'bg-amber-500/60',
  },
] as const;

function WeeklyReportCard({ report, defaultOpen }: { report: WeeklyReport; defaultOpen: boolean }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className='rounded-2xl border border-border/70 bg-background/80 shadow-sm shadow-black/5 overflow-hidden'>
      <button
        onClick={() => setOpen(!open)}
        className='w-full flex items-center justify-between gap-4 px-5 py-4 text-left hover:bg-muted/20 transition-colors'
      >
        <div className='flex items-center gap-3 min-w-0'>
          <span className='shrink-0 rounded-full bg-amber-500/15 px-2.5 py-1 text-[10px] font-semibold uppercase tracking-widest text-amber-600'>
            周报
          </span>
          <div className='min-w-0'>
            <p className='text-[11px] font-medium tracking-widest text-muted-foreground uppercase leading-none mb-1'>{report.dateRange}</p>
            <p className='text-sm font-semibold leading-snug tracking-tight truncate'>{report.headline}</p>
          </div>
        </div>
        <span className='shrink-0 text-muted-foreground text-base leading-none'>{open ? '−' : '+'}</span>
      </button>
      {open ? (
        <div className='border-t border-border/50 divide-y divide-border/40'>
          {SECTION_META.map(({ key, label, color, dot }) => {
            const items = report[key];
            if (!items || items.length === 0) return null;
            return (
              <div key={key} className='px-5 py-4 space-y-2.5'>
                <WeeklySectionTag label={label} color={color} />
                <ul className='space-y-1.5'>
                  {items.map((item, i) => (
                    <li key={i} className='flex items-start gap-2 text-sm text-muted-foreground leading-relaxed'>
                      <span className={`mt-[7px] h-1.5 w-1.5 shrink-0 rounded-full ${dot}`} />
                      {item}
                    </li>
                  ))}
                </ul>
              </div>
            );
          })}
        </div>
      ) : null}
    </div>
  );
}

function WeeklyResearchTab() {
  return (
    <div className='space-y-6'>
      <div className='space-y-1'>
        <h2 className='text-xl font-semibold tracking-tight'>Weekly Research</h2>
        <p className='text-sm text-muted-foreground'>
          每周加密货币、宏观经济与 AI 科技领域的研究更新，覆盖 Crypto · Macro · AI & Tech 三大维度。
        </p>
      </div>
      {WEEKLY_REPORTS.length === 0 ? (
        <p className='rounded-2xl border border-dashed border-border px-4 py-10 text-center text-sm text-muted-foreground'>
          暂无周报内容。
        </p>
      ) : (
        <div className='space-y-3'>
          {WEEKLY_REPORTS.map((report, i) => (
            <WeeklyReportCard key={report.id} report={report} defaultOpen={i === 0} />
          ))}
        </div>
      )}
    </div>
  );
}

