// Weekly Research data — edit this file to update reports.
// Add new entries at the TOP of the array (most recent first).

export interface WeeklyNewsItem {
  category: string;
  title: string;
  source: string;
  summary: string;
  action?: string;
}

interface GeoItem {
  title: string;
  subtitle: string;
  content: string;
}

interface WeeklyReport {
  id: string;
  dateRange: string;

